// MARK: - Token Storage

protocol TokenStorage {
    var accessToken: String? { get set }
    var refreshToken: String? { get set }
    func clearTokens()
}

final class KeychainTokenStorage: TokenStorage {
    static let shared = KeychainTokenStorage()
    
    private let accessTokenKey = "com.example.app.accessToken"
    private let refreshTokenKey = "com.example.app.refreshToken"
    
    private init() {}
    
    var accessToken: String? {
        get { return readFromKeychain(key: accessTokenKey) }
        set {
            if let value = newValue {
                saveToKeychain(key: accessTokenKey, value: value)
            } else {
                deleteFromKeychain(key: accessTokenKey)
            }
        }
    }
    
    var refreshToken: String? {
        get { return readFromKeychain(key: refreshTokenKey) }
        set {
            if let value = newValue {
                saveToKeychain(key: refreshTokenKey, value: value)
            } else {
                deleteFromKeychain(key: refreshTokenKey)
            }
        }
    }
    
    func clearTokens() {
        accessToken = nil
        refreshToken = nil
    }
    
    // MARK: - Keychain Helpers
    
    private func saveToKeychain(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        
        SecItemDelete(query as CFDictionary)
        
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemAdd(attributes as CFDictionary, nil)
    }
    
    private func readFromKeychain(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        
        return String(data: data, encoding: .utf8)
    }
    
    private func deleteFromKeychain(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Network Client Protocol

protocol NetworkClientProtocol {
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable?,
        queryParams: [String: String]?,
        requiresAuth: Bool
    ) async throws -> T
}

// MARK: - Network Client

final class NetworkClient: NetworkClientProtocol {
    
    static let shared = NetworkClient()
    
    private let session: URLSession
    private let environment: Environment
    private let tokenStorage: TokenStorage
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    
    private var isRefreshing = false
    private var refreshContinuations: [CheckedContinuation<String, Error>] = []
    private let refreshLock = NSLock()
    
    init(
        environment: Environment = NetworkClient.currentEnvironment(),
        tokenStorage: TokenStorage = KeychainTokenStorage.shared,
        sessionConfiguration: URLSessionConfiguration = .default
    ) {
        self.environment = environment
        self.tokenStorage = tokenStorage
        
        sessionConfiguration.timeoutIntervalForRequest = 30
        sessionConfiguration.timeoutIntervalForResource = 60
        sessionConfiguration.waitsForConnectivity = true
        
        self.session = URLSession(configuration: sessionConfiguration)
        
        self.decoder = JSONDecoder()
        self.decoder.dateDecodingStrategy = .iso8601
        
        self.encoder = JSONEncoder()
        self.encoder.dateEncodingStrategy = .iso8601
    }
    
    // MARK: - Environment Detection
    
    private static func currentEnvironment() -> Environment {
        #if DEBUG
        return .development
        #else
        if let envString = Bundle.main.infoDictionary?["APP_ENVIRONMENT"] as? String {
            switch envString.lowercased() {
            case "staging":
                return .staging
            case "production":
                return .production
            default:
                return .development
            }
        }
        return .production
        #endif
    }
    
    // MARK: - Request Building
    
    private func buildURL(endpoint: APIEndpoint, queryParams: [String: String]?) throws -> URL {
        let urlString = environment.baseURL + endpoint.path
        
        guard var components = URLComponents(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        if let queryParams = queryParams, !queryParams.isEmpty {
            components.queryItems = queryParams.map { URLQueryItem(name: $0.key, value: $0.value) }
        }
        
        guard let url = components.url else {
            throw NetworkError.invalidURL
        }
        
        return url
    }
    
    private func buildRequest(
        url: URL,
        method: HTTPMethod,
        body: Encodable?,
        requiresAuth: Bool,
        accessToken: String? = nil
    ) throws -> URLRequest {
        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        if requiresAuth {
            let token = accessToken ?? tokenStorage.accessToken
            guard let token = token else {
                throw NetworkError.unauthorized
            }
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            request.httpBody = try encoder.encode(body)
        }
        
        return request
    }
    
    // MARK: - Main Request Method
    
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable? = nil,
        queryParams: [String: String]? = nil,
        requiresAuth: Bool = true
    ) async throws -> T {
        let url = try buildURL(endpoint: endpoint, queryParams: queryParams)
        let urlRequest = try buildRequest(
            url: url,
            method: endpoint.method,
            body: body,
            requiresAuth: requiresAuth
        )
        
        do {
            return try await performRequest(urlRequest)
        } catch NetworkError.unauthorized where requiresAuth {
            // Attempt token refresh
            let newToken = try await refreshAccessToken()
            
            let retryRequest = try buildRequest(
                url: url,
                method: endpoint.method,
                body: body,
                requiresAuth: true,
                accessToken: newToken
            )
            
            return try await performRequest(retryRequest)
        }
    }
    
    // MARK: - Perform Request
    
    private func performRequest<T: Decodable>(_ request: URLRequest) async throws -> T {
        let data: Data
        let response: URLResponse
        
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            throw NetworkError.networkFailure(error)
        }
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.unknown
        }
        
        #if DEBUG
        logRequest(request, response: httpResponse, data: data)
        #endif
        
        switch httpResponse.statusCode {
        case 200...299:
            do {
                let decoded = try decoder.decode(T.self, from: data)
                return decoded
            } catch {
                throw NetworkError.decodingError(error)
            }
            
        case 401:
            throw NetworkError.unauthorized
            
        default:
            let errorMessage: String?
            if let apiError = try? decoder.decode(APIErrorResponse.self, from: data) {
                errorMessage = apiError.message
            } else {
                errorMessage = String(data: data, encoding: .utf8)
            }
            throw NetworkError.serverError(statusCode: httpResponse.statusCode, message: errorMessage)
        }
    }
    
    // MARK: - Token Refresh
    
    private func refreshAccessToken() async throws -> String {
        refreshLock.lock()
        
        if isRefreshing {
            refreshLock.unlock()
            // Wait for the ongoing refresh to complete
            return try await withCheckedThrowingContinuation { continuation in
                refreshLock.lock()
                refreshContinuations.append(continuation)
                refreshLock.unlock()
            }
        }
        
        isRefreshing = true
        refreshLock.unlock()
        
        defer {
            refreshLock.lock()
            isRefreshing = false
            refreshLock.unlock()
        }
        
        guard let currentRefreshToken = tokenStorage.refreshToken else {
            let error = NetworkError.unauthorized
            resolveRefreshContinuations(with: .failure(error))
            throw error
        }
        
        do {
            let refreshRequest = RefreshTokenRequest(refreshToken: currentRefreshToken)
            let url = try buildURL(endpoint: .refreshToken, queryParams: nil)
            let urlRequest = try buildRequest(
                url: url,
                method: .post,
                body: refreshRequest,
                requiresAuth: false
            )
            
            let response: RefreshTokenResponse = try await performRequest(urlRequest)
            
            var mutableStorage = tokenStorage
            mutableStorage.accessToken = response.accessToken
            mutableStorage.refreshToken = response.refreshToken
            
            resolveRefreshContinuations(with: .success(response.accessToken))
            
            return response.accessToken
        } catch {
            var mutableStorage = tokenStorage
            mutableStorage.clearTokens()
            
            resolveRefreshContinuations(with: .failure(NetworkError.unauthorized))
            throw NetworkError.unauthorized
        }
    }
    
    private func resolveRefreshContinuations(with result: Result<String, Error>) {
        refreshLock.lock()
        let continuations = refreshContinuations
        refreshContinuations.removeAll()
        refreshLock.unlock()
        
        for continuation in continuations {
            switch result {
            case .success(let token):
                continuation.resume(returning: token)
            case .failure(let error):
                continuation.resume(throwing: error)
            }
        }
    }
    
    // MARK: - Logging
    
    #if DEBUG
    private func logRequest(_ request: URLRequest, response: HTTPURLResponse, data: Data) {
        print("🌐 [\(request.httpMethod ?? "?")] \(request.url?.absoluteString ?? "unknown")")
        print("   Status: \(response.statusCode)")
        if let body = request.httpBody, let bodyString = String(data: body, encoding: .utf8) {
            print("   Request Body: \(bodyString)")
        }
        if let responseString = String(data: data, encoding: .utf8) {
            let truncated = responseString.prefix(500)
            print("   Response: \(truncated)")
        }
        print("---")
    }
    #endif
}

// MARK: - AnyEncodable wrapper for encoding generic Encodable

private struct AnyEncodable: Encodable {
    private let encodeFunc: (Encoder) throws -> Void
    
    init(_ wrapped: Encodable) {
        self.encodeFunc = wrapped.encode
    }
    
    func encode(to encoder: Encoder) throws {
        try encodeFunc(encoder)
    }
}

// MARK: - Encodable extension

private extension Encodable {
    func encode(to encoder: Encoder) throws {
        try self.encode(to: encoder)
    }
}

// MARK: - Auth Service

protocol AuthServiceProtocol {
    func login(email: String, password: String) async throws -> AuthResponse
    func register(email: String, password: String, name: String) async throws -> AuthResponse
    func logout()
}

final class AuthService: AuthServiceProtocol {
    
    static let shared = AuthService()
    
    private let networkClient: NetworkClientProtocol
    private var tokenStorage: TokenStorage
    
    init(
        networkClient: NetworkClientProtocol = NetworkClient.shared,
        tokenStorage: TokenStorage = KeychainTokenStorage.shared
    ) {
        self.networkClient = networkClient
        self.tokenStorage = tokenStorage
    }
    
    func login(email: String, password: String) async throws -> AuthResponse {
        let body = LoginRequest(email: email, password: password)
        
        let response: AuthResponse = try await networkClient.request(
            endpoint: .login,
            body: body,
            queryParams: nil,
            requiresAuth: false
        )
        
        tokenStorage.accessToken = response.accessToken
        tokenStorage.refreshToken = response.refreshToken
        
        return response
    }
    
    func register(email: String, password: String, name: String) async throws -> AuthResponse {
        let body = RegisterRequest(email: email, password: password, name: name)
        
        let response: AuthResponse = try await networkClient.request(
            endpoint: .register,
            body: body,
            queryParams: nil,
            requiresAuth: false
        )
        
        tokenStorage.accessToken = response.accessToken
        tokenStorage.refreshToken = response.refreshToken
        
        return response
    }
    
    func logout() {
        tokenStorage.clearTokens()
    }
}

// MARK: - User Service

protocol UserServiceProtocol {
    func fetchCurrentUser() async throws -> User
    func fetchUsers(page: Int, perPage: Int) async throws -> UsersResponse
    func fetchUser(id: String) async throws -> User
    func updateUser(id: String, name: String?, avatarURL: String?) async throws -> User
}

final class UserService: UserServiceProtocol {
    
    static let shared = UserService()
    
    private let networkClient: NetworkClientProtocol
    
    init(networkClient: NetworkClientProtocol = NetworkClient.shared) {
        self.networkClient = networkClient
    }
    
    func fetchCurrentUser() async throws -> User {
        return try await networkClient.request(
            endpoint: .userProfile,
            body: nil,
            queryParams: nil,
            requiresAuth: true
        )
    }
    
    func fetchUsers(page: Int = 1, perPage: Int = 20) async throws -> UsersResponse {
        let queryParams = [
            "page": String(page),
            "per_page": String(perPage)
        ]
        
        return try await networkClient.request(
            endpoint: .users,
            body: nil,
            queryParams: queryParams,
            requiresAuth: true
        )
    }
    
    func fetchUser(id: String) async throws -> User {
        return try await networkClient.request(
            endpoint: .user(id: id),
            body: nil,
            queryParams: nil,
            requiresAuth: true
        )
    }
    
    func updateUser(id: String, name: String?, avatarURL: String?) async throws -> User {
        let body = UpdateUserRequest(name: name, avatarURL: avatarURL)
        
        return try await networkClient.request(
            endpoint: .updateUser(id: id),
            body: body,
            queryParams: nil,
            requiresAuth: true
        )
    }
}

// MARK: - Usage Examples (ViewModel)

@MainActor
final class UserViewModel: ObservableObject {
    
    @Published var currentUser: User?
    @Published var users: [User] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var isAuthenticated = false
    
    private let authService: AuthServiceProtocol
    private let userService: UserServiceProtocol
    
    init(
        authService: AuthServiceProtocol = AuthService.shared,
        userService: UserServiceProtocol = UserService.shared
    ) {
        self.authService = authService
        self.userService = userService
    }
    
    func login(email: String, password: String) async {
        isLoading = true
        errorMessage = nil
        
        do {
            let response = try await authService.login(email: email, password: password)
            currentUser = response.user
            isAuthenticated = true
        } catch {
            errorMessage = (error as? NetworkError)?.errorDescription ?? error.localizedDescription
        }
        
        isLoading = false
    }
    
    func register(email: String, password: String, name: String) async {
        isLoading = true
        errorMessage = nil
        
        do {
            let response = try await authService.register(email: email, password: password, name: name)
            currentUser = response.user
            isAuthenticated = true
        } catch {
            errorMessage = (error as? NetworkError)?.errorDescription ?? error.localizedDescription
        }
        
        isLoading = false
    }
    
    func fetchProfile() async {
        isLoading = true
        errorMessage = nil
        
        do {
            currentUser = try await userService.fetchCurrentUser()
        } catch {
            errorMessage = (error as? NetworkError)?.errorDescription ?? error.localizedDescription
            if case NetworkError.unauthorized = error {
                isAuthenticated = false
            }
        }
        
        isLoading = false
    }
    
    func fetchUsers(page: Int = 1) async {
        isLoading = true
        errorMessage = nil
        
        do {
            let response = try await userService.fetchUsers(page: page)
            if page == 1 {
                users = response.users
            } else {
                users.append(contentsOf: response.users)
            }
        } catch {
            errorMessage = (error as? NetworkError)?.errorDescription ?? error.localizedDescription
        }
        
        isLoading = false
    }
    
    func logout() {
        authService.logout()
        currentUser = nil
        users = []
        isAuthenticated = false
    }
}